from collections import deque

graph = {
    "A": ["B", "C"],
    "B": ["A", "D", "E"],
    "C": ["A", "F"],
    "E": ["B", "F"],
}

def bfs(graph, start, goal):
    frontier = deque([[start]])
    visited = set()
    while frontier:
        path = frontier.popleft()
        node = path[-1]
        if node == goal:
            return path
        if node in visited:
            continue
        visited.add(node)
        for nb in graph.get(node, []):
            frontier.append(path + [nb])
    return None

print(bfs(graph, "A", "F"))

from collections import deque

def bfs(graph, start, goal):
    frontier = deque([[start]])
    while frontier:
        path = frontier.popleft()
        node = path[-1]
        if node == goal:
            return path
        for nb in graph[node]:
            frontier.append(path + [nb])
    return None
